import{c as t,Q as r,j as a,m as o}from"./chunks/framework.BXc4yaFE.js";const d=JSON.parse('{"title":"RCR-Router: Role-Aware Context Routing for Multi-Agent Systems","description":"","frontmatter":{"title":"RCR-Router: Role-Aware Context Routing for Multi-Agent Systems","arxiv_id":2508.04903,"authors":"Research team","published":"2025-08-01T00:00:00.000Z","source":"https://arxiv.org/abs/2508.04903","venue":"arXiv"},"headers":[],"relativePath":"research/papers/2025-08-01-rcr-router-role-aware-context-routing-2508.04903.md","filePath":"research/papers/2025-08-01-rcr-router-role-aware-context-routing-2508.04903.md","lastUpdated":1779894392000}'),i={name:"research/papers/2025-08-01-rcr-router-role-aware-context-routing-2508.04903.md"};function n(s,e,l,c,h,u){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="rcr-router-role-aware-context-routing-for-multi-agent-systems" tabindex="-1">RCR-Router: Role-Aware Context Routing for Multi-Agent Systems <a class="header-anchor" href="#rcr-router-role-aware-context-routing-for-multi-agent-systems" aria-label="Permalink to &quot;RCR-Router: Role-Aware Context Routing for Multi-Agent Systems&quot;">â€‹</a></h1><p><strong>Published</strong>: August 1, 2025</p><p><strong>Source</strong>: <a href="https://arxiv.org/abs/2508.04903" target="_blank" rel="noreferrer">https://arxiv.org/abs/2508.04903</a></p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">â€‹</a></h2><p>RCR-Router is a framework designed to improve efficiency in multi-agent large language model systems. The approach addresses a key limitation in existing systems: they typically rely on &quot;static or full-context routing strategies, which lead to excessive token consumption.&quot; The system introduces dynamic memory selection based on agent roles and task stages while maintaining strict token budgets.</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">â€‹</a></h2><p>This paper introduces RCR-Router, a framework that optimizes how multiple language model agents access shared memory during collaborative tasks. The system dynamically selects relevant information for each agent based on their assigned role and current task phase, while respecting strict token budgets.</p><hr><h2 id="key-innovation" tabindex="-1">Key Innovation <a class="header-anchor" href="#key-innovation" aria-label="Permalink to &quot;Key Innovation&quot;">â€‹</a></h2><p>The primary contribution addresses a critical limitation in existing multi-agent LLM systems: &quot;excessive token consumption, redundant memory exposure, and limited adaptability across interaction rounds.&quot; Rather than giving all agents access to complete memory (full-context routing) or using fixed, static allocations, RCR-Router implements semantic-aware, role-conditioned memory filtering.</p><hr><h2 id="core-mechanism" tabindex="-1">Core Mechanism <a class="header-anchor" href="#core-mechanism" aria-label="Permalink to &quot;Core Mechanism&quot;">â€‹</a></h2><p>The framework operates through three components:</p><ol><li><strong>Token Budget Allocator</strong>: Assigns maximum token limits to each agent based on role requirements</li><li><strong>Importance Scorer</strong>: Ranks memory items by relevance using role-specific keywords, task stage priority, and recency signals</li><li><strong>Semantic Filter</strong>: Greedily selects the highest-scoring items until token budgets are exhausted</li></ol><p>The system continuously updates shared memory with agent outputs, enabling iterative refinement across multiple reasoning rounds.</p><hr><h2 id="performance-results" tabindex="-1">Performance Results <a class="header-anchor" href="#performance-results" aria-label="Permalink to &quot;Performance Results&quot;">â€‹</a></h2><p>Testing across three question-answering benchmarks (HotPotQA, MuSiQue, 2WikiMultihop) demonstrates that RCR-Router achieves:</p><ul><li><strong>25-47% token reduction</strong> compared to full-context approaches</li><li><strong>Improved answer quality scores</strong> while consuming fewer resources</li><li><strong>Faster runtime</strong> with lower computational overhead</li></ul><p>Ablation studies confirm that performance saturates around 3-4 iterations, and diminishing returns appear with token budgets above 2,048 tokens per agent.</p><hr><h2 id="evaluation-methodology" tabindex="-1">Evaluation Methodology <a class="header-anchor" href="#evaluation-methodology" aria-label="Permalink to &quot;Evaluation Methodology&quot;">â€‹</a></h2><p>The researchers introduced an Answer Quality Score metric that evaluates LLM-generated explanations beyond standard accuracy metrics, providing more nuanced assessment of model behavior.</p><hr><h2 id="theoretical-grounding" tabindex="-1">Theoretical Grounding <a class="header-anchor" href="#theoretical-grounding" aria-label="Permalink to &quot;Theoretical Grounding&quot;">â€‹</a></h2><p>The authors prove that optimal context selection is NP-hard (equivalent to the 0/1 Knapsack problem), justifying their greedy heuristic approach. They also establish that iterative feedback loops monotonically improve expected context quality over interaction rounds.</p><hr><h2 id="technical-approach" tabindex="-1">Technical Approach <a class="header-anchor" href="#technical-approach" aria-label="Permalink to &quot;Technical Approach&quot;">â€‹</a></h2><p>The framework combines lightweight scoring policies for memory selection with structured memory storage to support adaptive multi-agent collaboration across interaction rounds.</p>',31)])])}const p=t(i,[["render",n]]);export{d as __pageData,p as default};
